const rows = $input.all();
const filtered = rows.filter(item => {
  const cls = (item.json.classification || '').toLowerCase().trim();
  return cls === 'decentralized' || cls === 'hybrid';
});
if (filtered.length === 0) throw new Error('No Decentralized or Hybrid firms found');
return filtered.map(item => ({ json: {
  pe_firm_name:       item.json.pe_firm_name || '',
  classification:     item.json.classification || '',
  website_url:        item.json.website_url || '',
  portfolio_page_url: item.json.portfolio_page_url || '',
  company_country:    item.json.company_country || '',
  run_date:           new Date().toISOString().split('T')[0]
}}));

const firm = $('Loop Over Firms1').item.json;
const aiResp = $('Portfolio Extraction AI').first().json;
let raw = aiResp.output || aiResp.text || '';
let ai = {};

try {
  const m = raw.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('no JSON found');
  ai = JSON.parse(m[0]);
} catch(e) {
  ai = { pe_firm_name: firm.pe_firm_name, total_found: 0, portfolio_companies: [] };
}

const companies = (ai.portfolio_companies || []).filter(pc => pc.company_name && pc.company_name.trim() !== '');

// Deduplicate by company_name (case-insensitive)
const seen = new Set();
const unique = companies.filter(pc => {
  const key = pc.company_name.toLowerCase().trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (unique.length === 0) {
  return [{ json: {
    pe_firm_name:   firm.pe_firm_name,
    classification: firm.classification,
    company_name:   'NO PORTFOLIO DATA FOUND',
    industry:       '', region: '', hq_country: '', website: '',
    total_found:    0,
    run_date:       firm.run_date
  }}];
}

return unique.map((pc, idx) => ({ json: {
  pe_firm_name:   firm.pe_firm_name,
  classification: firm.classification,
  company_name:   pc.company_name.trim(),
  industry:       pc.industry   || '',
  region:         pc.region     || '',
  hq_country:     pc.hq_country || '',
  website:        pc.website    || '',
  total_found:    unique.length,
  run_date:       firm.run_date
}}));

// ── Smart Data Cleaner ──
// Saara raw data leke sirf useful text nikaalte hain

const firm = $('Loop Over Firms1').item.json;

// Helper: HTML tags hatao
function stripHtml(str) {
  if (!str) return '';
  return str
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ').replace(/&#\d+;/g, ' ')
    .replace(/\s{3,}/g, '\n')
    .trim();
}

// Helper: Ek source ka text nikalo
function extractText(nodeRef, fieldChain) {
  try {
    let data = nodeRef;
    for (const f of fieldChain) {
      if (data === null || data === undefined) return '';
      data = data[f];
    }
    return (data || '').toString();
  } catch(e) { return ''; }
}

// ── Collect raw texts from all sources ──
const sources = [];

// Source 1: Direct HTTP fetch
try {
  if ($('Fetch 1 — Portfolio Page Direct').isExecuted) {
    const raw = $('Fetch 1 — Portfolio Page Direct').first().json;
    const text = stripHtml(raw.data || raw.body || raw.html || '');
    if (text.length > 100) sources.push({ name: 'HTTP_FETCH', text });
  }
} catch(e) {}

// Source 2: Tavily Extract (JS rendered)
try {
  if ($('Fetch 2 — Tavily Extract (JS Rendered)').isExecuted) {
    const results = $('Fetch 2 — Tavily Extract (JS Rendered)').first().json.results || [];
    const text = results.map(r => r.raw_content || r.text || '').join('\n');
    if (text.length > 100) sources.push({ name: 'TAVILY_EXTRACT', text: text.slice(0, 4000) });
  }
} catch(e) {}

// Sources 3-7: Tavily searches
const searchNodes = [
  'Search 1 — Full Portfolio List',
  'Search 2 — Sector Portfolio',
  'Search 3 — Region Portfolio',
  'Search 4 — Crunchbase & News',
  'Search 5 — Deal News'
];

for (const nodeName of searchNodes) {
  try {
    if ($(nodeName).isExecuted) {
      const data = $(nodeName).first().json;
      const answer = data.answer || '';
      const results = (data.results || []).map(r => `${r.title}: ${r.content}`).join('\n');
      const combined = (answer + '\n' + results).trim();
      if (combined.length > 50) sources.push({ name: nodeName, text: combined });
    }
  } catch(e) {}
}

// ── Smart Filter: sirf company-relevant lines rakho ──
function isRelevantLine(line) {
  const l = line.toLowerCase();
  // Skip navigation/footer garbage
  const skipWords = ['cookie', 'privacy policy', 'terms of use', 'copyright', 
    'all rights reserved', 'sign in', 'log in', 'subscribe', 'newsletter',
    'facebook', 'twitter', 'linkedin.com', 'instagram', 'youtube',
    'menu', 'search', 'home', 'about us', 'contact us', 'careers at',
    'javascript', 'function(', 'var ', 'const ', 'window.', 'document.',
    '<!doctype', '<html', 'css', '.js', 'analytics', 'gtag'];
  if (skipWords.some(w => l.includes(w))) return false;
  // Must be reasonable length
  if (line.trim().length < 5 || line.trim().length > 300) return false;
  return true;
}

// Combine all sources, clean line by line
const allLines = new Set();
for (const src of sources) {
  const lines = src.text.split('\n');
  for (const line of lines) {
    const cleaned = line.trim();
    if (isRelevantLine(cleaned)) {
      allLines.add(cleaned);
    }
  }
}

// Join and limit to ~6000 chars so AI gets focused input
const cleanedText = Array.from(allLines).join('\n').slice(0, 6000);

return [{ json: {
  pe_firm_name:       firm.pe_firm_name,
  classification:     firm.classification,
  portfolio_page_url: firm.portfolio_page_url || '',
  website_url:        firm.website_url || '',
  run_date:           firm.run_date,
  cleaned_text:       cleanedText,
  sources_used:       sources.map(s => s.name),
  raw_char_count:     sources.reduce((a, s) => a + s.text.length, 0),
  cleaned_char_count: cleanedText.length
}}];
